namespace sv_07f87631501d44a191139ffd12ab8fb1.Services;

public record Channel(int Id, string Name, string Description, int UnreadCount);
public record Message(int Id, int ChannelId, string Author, string Content, DateTime SentAt, int? ReplyToId, List<Reaction> Reactions);
public record Reaction(string Emoji, List<string> Users);
public record ThreadSummary(int RootMessageId, int ReplyCount, DateTime LastReplyAt);

namespace sv_07f87631501d44a191139ffd12ab8fb1.Services;

public interface IChatService
{
    Task<List<Channel>> GetChannelsAsync();
    Task<List<Message>> GetMessagesAsync(int channelId, int skip, int take);
    Task<Message> SendMessageAsync(int channelId, string content, int? replyToId);
    Task<List<Message>> GetThreadAsync(int rootMessageId);
    Task AddReactionAsync(int messageId, string emoji);
    Task MarkChannelReadAsync(int channelId);
}

namespace sv_07f87631501d44a191139ffd12ab8fb1.Services;

public class MockChatService : IChatService
{
    private readonly List<Channel> _channels;
    private readonly List<Message> _messages;
    private int _nextMessageId;

    public MockChatService()
    {
        _channels = new()
        {
            new(1, "general", "General discussion for the team", 3),
            new(2, "engineering", "Engineering topics and code reviews", 0),
            new(3, "design", "Design discussions and feedback", 1),
            new(4, "random", "Off-topic and fun stuff", 5),
            new(5, "announcements", "Important team announcements", 0),
        };

        var now = DateTime.UtcNow;
        _messages = new()
        {
            new(1, 1, "Alice", "Hey everyone! Welcome to the team chat.", now.AddHours(-5), null, new() { new("👋", new() { "Bob", "Carol" }), new("🎉", new() { "Dave" }) }),
            new(2, 1, "Bob", "Thanks Alice! Glad to be here.", now.AddHours(-4.5), null, new()),
            new(3, 1, "Carol", "Has anyone reviewed the latest PR?", now.AddHours(-3), null, new() { new("👀", new() { "Alice" }) }),
            new(4, 1, "Dave", "I'll take a look at it now.", now.AddHours(-2.5), 3, new()),
            new(5, 1, "Alice", "Great, let me know if you have questions.", now.AddHours(-2), 3, new()),
            new(6, 1, "Bob", "The new feature is looking really good!", now.AddMinutes(-45), null, new() { new("🚀", new() { "Alice", "Carol", "Dave" }) }),
            new(7, 1, "Carol", "Agreed! Nice work everyone.", now.AddMinutes(-30), null, new()),
            new(8, 1, "Dave", "Should we schedule a demo for Friday?", now.AddMinutes(-10), null, new() { new("👍", new() { "Alice", "Bob" }) }),
            new(9, 2, "Alice", "Let's discuss the architecture for the new service.", now.AddHours(-6), null, new()),
            new(10, 2, "Bob", "I think we should use a microservices approach.", now.AddHours(-5), 9, new()),
            new(11, 2, "Carol", "Here's the link to the design doc.", now.AddHours(-3), null, new()),
            new(12, 3, "Dave", "New mockups are uploaded to Figma.", now.AddHours(-1), null, new() { new("🎨", new() { "Carol" }) }),
        };
        _nextMessageId = 13;
    }

    public Task<List<Channel>> GetChannelsAsync()
        => Task.FromResult(_channels.Select(c => c with { }).ToList());

    public Task<List<Message>> GetMessagesAsync(int channelId, int skip, int take)
    {
        var msgs = _messages
            .Where(m => m.ChannelId == channelId && m.ReplyToId == null)
            .OrderByDescending(m => m.SentAt)
            .Skip(skip)
            .Take(take)
            .OrderBy(m => m.SentAt)
            .ToList();
        return Task.FromResult(msgs);
    }

    public Task<Message> SendMessageAsync(int channelId, string content, int? replyToId)
    {
        var msg = new Message(_nextMessageId++, channelId, "You", content, DateTime.UtcNow, replyToId, new());
        _messages.Add(msg);
        return Task.FromResult(msg);
    }

    public Task<List<Message>> GetThreadAsync(int rootMessageId)
    {
        var root = _messages.FirstOrDefault(m => m.Id == rootMessageId);
        var replies = _messages.Where(m => m.ReplyToId == rootMessageId).OrderBy(m => m.SentAt).ToList();
        var result = new List<Message>();
        if (root != null) result.Add(root);
        result.AddRange(replies);
        return Task.FromResult(result);
    }

    public Task AddReactionAsync(int messageId, string emoji)
    {
        var msg = _messages.FirstOrDefault(m => m.Id == messageId);
        if (msg != null)
        {
            var existing = msg.Reactions.FirstOrDefault(r => r.Emoji == emoji);
            if (existing != null)
            {
                if (!existing.Users.Contains("You"))
                    existing.Users.Add("You");
            }
            else
            {
                msg.Reactions.Add(new Reaction(emoji, new() { "You" }));
            }
        }
        return Task.CompletedTask;
    }

    public Task MarkChannelReadAsync(int channelId)
    {
        var idx = _channels.FindIndex(c => c.Id == channelId);
        if (idx >= 0)
            _channels[idx] = _channels[idx] with { UnreadCount = 0 };
        return Task.CompletedTask;
    }
}

