arguments.file_text:
@namespace sv_07f87631501d44a191139ffd12ab8fb1.Components.Chat

<div class="channel-item @(IsActive ? "active" : "")" @onclick="OnClick">
    <div class="channel-name-row">
        <span class="channel-name"># @Channel.Name</span>
        @if (Channel.UnreadCount > 0)
        {
            <span class="unread-badge">@Channel.UnreadCount</span>
        }
    </div>
    <span class="channel-desc">@TruncateDescription(Channel.Description)</span>
</div>

@code {
    [Parameter, EditorRequired] public required Services.Channel Channel { get; set; }
    [Parameter] public bool IsActive { get; set; }
    [Parameter] public EventCallback OnClick { get; set; }

    private string TruncateDescription(string desc)
        => desc.Length > 30 ? desc[..30] + "…" : desc;
}

.channel-item {
    padding: 8px 12px;
    cursor: pointer;
    border-radius: 6px;
    margin: 2px 6px;
    transition: background-color 0.15s;
}

.channel-item:hover {
    background-color: rgba(255, 255, 255, 0.1);
}

.channel-item.active {
    background-color: rgba(255, 255, 255, 0.15);
    border-left: 3px solid #5865f2;
    padding-left: 9px;
}

.channel-name-row {
    display: flex;
    justify-content: space-between;
    align-items: center;
}

.channel-name {
    font-weight: 600;
    font-size: 0.95rem;
    color: #dcddde;
}

.channel-item.active .channel-name {
    color: #fff;
}

.channel-desc {
    font-size: 0.75rem;
    color: #8e9297;
    display: block;
    margin-top: 2px;
    white-space: nowrap;
    overflow: hidden;
    text-overflow: ellipsis;
}

.unread-badge {
    background-color: #ed4245;
    color: #fff;
    font-size: 0.7rem;
    font-weight: 700;
    padding: 1px 6px;
    border-radius: 10px;
    min-width: 18px;
    text-align: center;
}

@namespace sv_07f87631501d44a191139ffd12ab8fb1.Components.Chat

<div class="channel-sidebar">
    <div class="sidebar-header">
        <h3>Channels</h3>
    </div>
    <div class="channel-list">
        @foreach (var channel in Channels)
        {
            <ChannelItem Channel="channel"
                         IsActive="channel.Id == ActiveChannelId"
                         OnClick="() => OnChannelSelected.InvokeAsync(channel.Id)" />
        }
    </div>
</div>

@code {
    [Parameter, EditorRequired] public required List<Services.Channel> Channels { get; set; }
    [Parameter] public int ActiveChannelId { get; set; }
    [Parameter] public EventCallback<int> OnChannelSelected { get; set; }
