    background-color: rgba(255, 255, 255, 0.15);
    border-left: 3px solid #5865f2;
    padding-left: 9px;
}

.channel-name-row {
    display: flex;
    justify-content: space-between;
    align-items: center;
}

.channel-name {
    font-weight: 600;
    font-size: 0.95rem;
    color: #dcddde;
}

.channel-item.active .channel-name {
    color: #fff;
}

.channel-desc {
    font-size: 0.75rem;
    color: #8e9297;
    display: block;
    margin-top: 2px;
    white-space: nowrap;
