@namespace sv_07f87631501d44a191139ffd12ab8fb1.Components.Chat
@inject IJSRuntime JS

<div class="message-list" @ref="_scrollContainer" @onscroll="HandleScroll">
    @if (_loadingMore)
    {
        <div class="loading-indicator">Loading older messages…</div>
    }
    @foreach (var msg in Messages)
    {
        <MessageItem Message="msg"
                     ReplyCount="GetReplyCount(msg.Id)"
                     OnOpenThread="OnOpenThread"
                     OnReact="OnReact" />
    }
</div>

@code {
    [Parameter, EditorRequired] public required List<Services.Message> Messages { get; set; }
    [Parameter] public Dictionary<int, int> ThreadReplyCounts { get; set; } = new();
    [Parameter] public EventCallback<int> OnOpenThread { get; set; }
    [Parameter] public EventCallback<(int MessageId, string Emoji)> OnReact { get; set; }
    [Parameter] public EventCallback OnLoadOlder { get; set; }

    private ElementReference _scrollContainer;
    private bool _loadingMore;

    private int GetReplyCount(int messageId)
        => ThreadReplyCounts.TryGetValue(messageId, out var count) ? count : 0;

    private async Task HandleScroll()
    {
        if (_loadingMore) return;

        var scrollTop = await JS.InvokeAsync<double>("eval",
            $"document.querySelector('[_bl_{_scrollContainer.Id}]')?.scrollTop ?? 1");

        if (scrollTop < 10)
        {
            _loadingMore = true;
            StateHasChanged();
            await OnLoadOlder.InvokeAsync();
            _loadingMore = false;
        }
    }

    public async Task ScrollToBottom()
    {
        await Task.Yield();
        try
        {
            await JS.InvokeVoidAsync("eval",
                $"(() => {{ var el = document.querySelector('[_bl_{_scrollContainer.Id}]'); if(el) el.scrollTop = el.scrollHeight; }})()");
        }
        catch { /* Element may not exist yet */ }
    }
}

.message-list {
    flex: 1;
    overflow-y: auto;
    padding: 8px 0;
    display: flex;
    flex-direction: column;
    gap: 2px;
}

.loading-indicator {
    text-align: center;
    padding: 12px;
    color: #72767d;
    font-size: 0.85rem;
}

@namespace sv_07f87631501d44a191139ffd12ab8fb1.Components.Chat

<div class="thread-panel">
