toolArgs.file_text:
@namespace sv_07f87631501d44a191139ffd12ab8fb1.Components.Chat

<div class="thread-panel">
    <div class="thread-header">
        <h4>Thread</h4>
        <button class="close-btn" @onclick="OnClose" title="Close thread">✕</button>
    </div>

    @if (RootMessage is not null)
    {
        <div class="thread-root-quote">
            <MessageItem Message="RootMessage" ShowActions="false" />
        </div>
    }

    <div class="thread-replies">
        @if (Replies.Count > 0)
        {
            @foreach (var reply in Replies)
            {
                <MessageItem Message="reply" ShowActions="false" />
            }
        }
        else
        {
            <div class="no-replies">No replies yet. Start the conversation!</div>
        }
    </div>

    <MessageInput Placeholder="Reply in thread…"
                  ButtonLabel="Reply"
                  OnSend="OnSendReply" />
</div>

@code {
    [Parameter] public Services.Message? RootMessage { get; set; }
    [Parameter] public List<Services.Message> Replies { get; set; } = new();
    [Parameter] public EventCallback OnClose { get; set; }
    [Parameter] public EventCallback<string> OnSendReply { get; set; }
}

.thread-panel {
    background-color: #36393f;
    border-left: 1px solid rgba(255, 255, 255, 0.06);
    height: 100%;
    display: flex;
    flex-direction: column;
    overflow: hidden;
}

.thread-header {
    display: flex;
    justify-content: space-between;
    align-items: center;
    padding: 12px 16px;
    border-bottom: 1px solid rgba(255, 255, 255, 0.06);
    flex-shrink: 0;
}

.thread-header h4 {
    margin: 0;
    font-size: 1rem;
    font-weight: 700;
    color: #fff;
}

.close-btn {
    background: transparent;
    border: none;
    color: #b9bbbe;
    font-size: 1.1rem;
    cursor: pointer;
    padding: 4px 8px;
    border-radius: 4px;
    line-height: 1;
}

.close-btn:hover {
    background-color: rgba(255, 255, 255, 0.1);
    color: #fff;
}

.thread-root-quote {
    border-bottom: 1px solid rgba(255, 255, 255, 0.06);
    background-color: rgba(0, 0, 0, 0.1);
    flex-shrink: 0;
}

.thread-replies {
    flex: 1;
    overflow-y: auto;
    padding: 8px 0;
}

.no-replies {
    text-align: center;
    color: #72767d;
    font-size: 0.85rem;
    padding: 24px 16px;
}

