@page "/chat"
@layout sv_07f87631501d44a191139ffd12ab8fb1.Components.Layout.ChatLayout
@rendermode InteractiveServer
@using sv_07f87631501d44a191139ffd12ab8fb1.Components.Chat
@using sv_07f87631501d44a191139ffd12ab8fb1.Services
@inject IChatService ChatService

<div class="chat-page">
    <div class="chat-sidebar">
        <ChannelSidebar Channels="_channels"
                        ActiveChannelId="_activeChannelId"
                        OnChannelSelected="SelectChannel" />
    </div>

    <div class="chat-main @(_threadOpen ? "" : "expanded")">
        <MessageArea @ref="_messageArea"
                     Channel="_activeChannel"
                     Messages="_messages"
                     ThreadReplyCounts="_threadReplyCounts"
                     OnOpenThread="OpenThread"
                     OnReact="AddReaction"
                     OnSendMessage="SendMessage"
                     OnLoadOlder="LoadOlderMessages" />
    </div>

    @if (_threadOpen)
    {
        <div class="chat-thread">
            <ThreadPanel RootMessage="_threadRootMessage"
                         Replies="_threadReplies"
                         OnClose="CloseThread"
                         OnSendReply="SendThreadReply" />
        </div>
    }
</div>

@code {
    private List<Channel> _channels = new();
    private List<Message> _messages = new();
    private int _activeChannelId;
    private Channel? _activeChannel;
    private int _skip;
    private const int PageSize = 20;

    // Thread state
    private bool _threadOpen;
    private int _threadRootId;
    private Message? _threadRootMessage;
    private List<Message> _threadReplies = new();

    // Reply counts for thread indicators
    private Dictionary<int, int> _threadReplyCounts = new();

    private MessageArea? _messageArea;

    protected override async Task OnInitializedAsync()
    {
        _channels = await ChatService.GetChannelsAsync();
        if (_channels.Count > 0)
            await SelectChannel(_channels[0].Id);
    }

    private async Task SelectChannel(int channelId)
    {
        _activeChannelId = channelId;
        _activeChannel = _channels.FirstOrDefault(c => c.Id == channelId);
        _skip = 0;
        _messages = await ChatService.GetMessagesAsync(channelId, 0, PageSize);
        _threadOpen = false;

        await ChatService.MarkChannelReadAsync(channelId);
        _channels = await ChatService.GetChannelsAsync();

        await UpdateThreadReplyCounts();

        StateHasChanged();
        if (_messageArea is not null)
            await _messageArea.ScrollToBottom();
    }

    private async Task LoadOlderMessages()
    {
        _skip += PageSize;
        var older = await ChatService.GetMessagesAsync(_activeChannelId, _skip, PageSize);
        if (older.Count > 0)
        {
            _messages.InsertRange(0, older);
            await UpdateThreadReplyCounts();
        }
    }

    private async Task SendMessage(string content)
    {
        var msg = await ChatService.SendMessageAsync(_activeChannelId, content, null);
        _messages.Add(msg);
        StateHasChanged();
        if (_messageArea is not null)
            await _messageArea.ScrollToBottom();
    }

    private async Task OpenThread(int rootMessageId)
    {
        _threadRootId = rootMessageId;
        var threadMessages = await ChatService.GetThreadAsync(rootMessageId);
        _threadRootMessage = threadMessages.FirstOrDefault();
        _threadReplies = threadMessages.Skip(1).ToList();
        _threadOpen = true;
    }

    private void CloseThread()
    {
        _threadOpen = false;
    }

    private async Task SendThreadReply(string content)
    {
        var reply = await ChatService.SendMessageAsync(_activeChannelId, content, _threadRootId);
        _threadReplies.Add(reply);

        // Update reply count
        _threadReplyCounts[_threadRootId] = _threadReplies.Count;
    }

    private async Task AddReaction((int MessageId, string Emoji) args)
    {
        await ChatService.AddReactionAsync(args.MessageId, args.Emoji);

        // Refresh messages to show updated reactions
        _messages = await ChatService.GetMessagesAsync(_activeChannelId, 0, _skip + PageSize);
    }

    private async Task UpdateThreadReplyCounts()
    {
        _threadReplyCounts.Clear();
        foreach (var msg in _messages)
        {
            var thread = await ChatService.GetThreadAsync(msg.Id);
            var replyCount = thread.Count - 1; // exclude root
            if (replyCount > 0)
                _threadReplyCounts[msg.Id] = replyCount;
        }
    }
}

