    display: flex;
    height: 100vh;
    width: 100%;
    overflow: hidden;
}

.chat-sidebar {
    width: 20%;
    min-width: 200px;
    max-width: 280px;
    flex-shrink: 0;
}

.chat-main {
    flex: 1;
    min-width: 0;
}

.chat-main.expanded {
    flex: 1;
}

.chat-thread {
    width: 25%;
    min-width: 280px;
    max-width: 400px;
    flex-shrink: 0;
}

